#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int is_prime(int n) {
    if (n <= 1) return 0;
    if (n == 2) return 1;
    if (n % 2 == 0) return 0;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return 0;
    }
    return 1;
}

int count_submatrices(int** matrix, int n, int m, int k) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            for (int x = i; x < n; x++) {
                for (int y = j; y < m; y++) {
                    int product = 1;
                    for (int a = i; a <= x; a++) {
                        for (int b = j; b <= y; b++) {
                            product *= matrix[a][b];
                        }
                    }
                    if (product == k) count++;
                }
            }
        }
    }
    return count;
}

int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    int** matrix = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        matrix[i] = (int*)malloc(m * sizeof(int));
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }
    printf("%d\n", count_submatrices(matrix, n, m, k));
    return 0;
}

